@see: Functions L{flatLocal_} or L{hubeny_}, L{cosineLaw}, L{flatPolar},
      L{cosineAndoyerLambert}, L{cosineForsytheAndoyerLambert},
      L{equirectangular}, L{euclidean}, L{haversine}, L{thomas},
