@kwarg falsed: If C{True}, false both easting and northing (C{bool}).
@kwarg strict: Restrict B{C{lat}} to UPS ranges (C{bool}).
@kwarg name: Optional B{C{Ups}} C{B{name}=NN} (C{str}).

